// Toggle heartbeat value between 0 and 1
const prev = flow.get('heartbeat') || 0;
const next = prev === 0 ? 1 : 0;
flow.set('heartbeat', next);
msg.payload = next;
return msg;

// Detect if heartbeat register stops toggling
const now = Date.now();
const current = msg.payload.data[0];
const prev = flow.get('lastHeartbeat');
const lastChange = flow.get('lastChangeTime') || now;

if (prev !== undefined && prev !== current) {
    flow.set('lastChangeTime', now);
} else if (now - lastChange > 10000) {
    // No change in 10 seconds → watchdog alarm
    msg.payload = { alarm: true, lastValue: current, staleSince: new Date(lastChange).toISOString() };
    msg.topic = 'watchdog/alarm';
    flow.set('lastHeartbeat', current);
    return [null, msg];
}

flow.set('lastHeartbeat', current);
msg.topic = 'watchdog/ok';
return [msg, null];
